import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class GsonBuilderTest {

  @Test
  void serializeNulls_shouldSetSerializeNullsTrueAndReturnThis() throws Exception {
    GsonBuilder gsonBuilder = new GsonBuilder();

    // Initially, serializeNulls field should be default (false or as per DEFAULT_SERIALIZE_NULLS)
    var serializeNullsField = GsonBuilder.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);
    boolean before = (boolean) serializeNullsField.get(gsonBuilder);

    // Call serializeNulls method
    GsonBuilder returned = gsonBuilder.serializeNulls();

    // After calling, serializeNulls field should be true
    boolean after = (boolean) serializeNullsField.get(gsonBuilder);

    // Assert the method returns the same instance
    assertSame(gsonBuilder, returned);

    // Assert the serializeNulls field changed from default to true
    assertFalse(before, "serializeNulls should initially be false (default)");
    assertTrue(after, "serializeNulls should be true after calling serializeNulls()");
  }
}
